parameters.query:
=SELECT *
FROM public.order_summary
WHERE chat_id = {{ $('Start').first().json.tool_input.chat_id }}
ORDER BY order_created_at DESC
LIMIT 1;

parameters.jsCode:
const root = (() => {
  try {
    const start = $('Start').first();
    if (start && start.json) return start.json;
  } catch {}
  if ($json && typeof $json === 'object' && Object.keys($json).length > 0) return $json;
  try {
    const current = $input.first();
    return (current && current.json) ? current.json : {};
  } catch {}
  return {};
})();
const toolInput = (root.tool_input && typeof root.tool_input === 'object') ? root.tool_input : root;
const chatId = String(toolInput.chat_id || '');
const orderId = String(toolInput.order_id || '');
const message = orderId
  ? 'No order found with ID #' + orderId + '. Please check and try again.'
  : 'You have no orders yet. Start shopping and I will build the cart for you.';
return [{ json: {
  confirmation_message: message,
  chat_id: String(chatId),
  message_type: 'button',
  buttons: [
    { id: 'browse', title: 'Shop Items' },
    { id: 'get_promos', title: 'Offers' },
  ],
} }];

const order = $('Order Found?').first().json;
const items = $('Get Order Items').all().map((entry) => entry.json);
const root = (() => {
  try {
    const start = $('Start').first();
    if (start && start.json) return start.json;
  } catch {}
  if ($json && typeof $json === 'object' && Object.keys($json).length > 0) return $json;
  try {
    const current = $input.first();
    return (current && current.json) ? current.json : {};
  } catch {}
  return {};
})();
const toolInput = (root.tool_input && typeof root.tool_input === 'object') ? root.tool_input : root;
const chatId = String(toolInput.chat_id || '');

let liveStatus = 'confirmed';
try {
  const liveRow = $('Get Live Status').first().json;
  if (liveRow && liveRow.status) liveStatus = liveRow.status;
} catch (error) {}

const statusLabel = {
  confirmed: 'Order received',
  processing: 'Packing your order',
  packed: 'Packed and getting ready',
  dispatched: 'On the way',
  delivered: 'Delivered',
  rejected: 'Could not be fulfilled',
  cancelled: 'Cancelled',
  pending_confirmation: 'Pending confirmation',
  pending_acceptance: 'Waiting for store acceptance',
}[liveStatus] || liveStatus;

const orderDate = new Date(order.order_created_at).toLocaleDateString('en-IN', {
  day: '2-digit', month: 'short', year: 'numeric',
});

const itemLines = items.map((entry) => '• ' + entry.name + ' × ' + entry.quantity).join('\n');
const message =
  'Order #' + order.order_id + '\n' +
  'Status: ' + statusLabel + '\n' +
  'Placed: ' + orderDate + '\n' +
  'Deliver to: ' + order.shipping_address + '\n\n' +
  'Items:\n' + itemLines + '\n\n' +
  'Total paid: ₹' + parseFloat(order.final_order_total).toFixed(2);

if (liveStatus === 'delivered') {
  return [{ json: {
    confirmation_message: message,
    chat_id: String(chatId),
    customer_ui_state: 'TRACKING',
    message_type: 'list',
    list_sections: [{
      title: 'What next?',
      rows: [
        { id: 'rate_good__' + order.order_id, title: 'All good', description: 'Close this order positively' },
        { id: 'rate_bad__' + order.order_id, title: 'Report issue', description: 'Share a problem with this delivery' },
        { id: 'browse', title: 'Shop again', description: 'Start a fresh order' },
      ],
    }],
  } }];
}

return [{ json: {
  confirmation_message: message,
  chat_id: String(chatId),
  customer_ui_state: 'TRACKING',
  message_type: 'button',
  buttons: [
    { id: 'browse', title: 'Shop Again' },
    { id: 'view_cart', title: '🛒 View Cart' },
  ],
} }];

